   216→type editResult struct {
   217→	FromX int    `json:"from_x"`
   218→	FromY int    `json:"from_y"`
   219→	ToX   int    `json:"to_x"`
   220→	ToY   int    `json:"to_y"`
   221→	Old   string `json:"old"`
   222→}
   223→
   224→func (c *editorEditCLI) Run(
   225→	ctx context.Context, args []string,
   226→) (retErr error) {
   227→	defer func() {
   228→		retErr = formatError(c.format, retErr)
   229→	}()
   230→	rargs, _, ok, err := cli.ParseUsage(
   231→		c, c.fs, 6, args,
   232→	)
   233→	if !ok || err != nil {
   234→		return err
   235→	}
   236→	h, err := getEditorHandler(ctx, c.app, rargs[0])
   237→	if err != nil {
   238→		return err
   239→	}
   240→	startX, err := strconv.Atoi(rargs[1])
   241→	if err != nil {
   242→		return fmt.Errorf("invalid start-x: %w", err)
   243→	}
   244→	startY, err := strconv.Atoi(rargs[2])
   245→	if err != nil {
   246→		return fmt.Errorf("invalid start-y: %w", err)
   247→	}
   248→	endX, err := strconv.Atoi(rargs[3])
   249→	if err != nil {
   250→		return fmt.Errorf("invalid end-x: %w", err)
   251→	}
   252→	endY, err := strconv.Atoi(rargs[4])
   253→	if err != nil {
   254→		return fmt.Errorf("invalid end-y: %w", err)
   255→	}
   256→	text := rargs[5]
   257→	w, err := c.app.getWorkspace()
   258→	if err != nil {
   259→		return err
   260→	}
   261→	start := term.Coordinates{X: startX, Y: startY}
   262→	end := term.Coordinates{X: endX, Y: endY}
   263→	from, to, old, err := w.Editor(ctx).CellEditor(
   264→		h,
   265→	).Edit(ctx, start, end, text)
   266→	if err != nil {
   267→		return err
   268→	}
   269→	res := editResult{
   270→		FromX: from.X, FromY: from.Y,
   271→		ToX: to.X, ToY: to.Y,
   272→		Old: old,
   273→	}
   274→	return printResult(
   275→		ctx, c.format, res,
   276→		func(v editResult) {
   277→			fmt.Printf(
   278→				"%d %d %d %d %s\n",
   279→				v.FromX, v.FromY,
   280→				v.ToX, v.ToY, v.Old,
   281→			)
   282→		},
   283→		[]string{
   284→			"FromX", "FromY", "ToX", "ToY", "Old",
   285→		},
   286→	)
   287→}
