   358→type jsonLocation struct {
   359→	From    jsonCoord `json:"from"`
   360→	To      jsonCoord `json:"to"`
   361→	Message string    `json:"message"`
   362→}
   363→
   364→type jsonCoord struct {
   365→	X int `json:"x"`
   366→	Y int `json:"y"`
   367→}
   368→
   369→func (c *locationsSetCLI) Run(
   370→	ctx context.Context, args []string,
   371→) (retErr error) {
   372→	defer func() {
   373→		retErr = formatError(c.format, retErr)
   374→	}()
   375→	rargs, _, ok, err := cli.ParseUsage(
   376→		c, c.fs, 4, args,
   377→	)
   378→	if !ok || err != nil {
   379→		return err
   380→	}
   381→	priority, err := parseLocationPriority(rargs[1])
   382→	if err != nil {
   383→		return err
   384→	}
   385→	id := rargs[2]
   386→	var locs []jsonLocation
   387→	if err := json.Unmarshal(
   388→		[]byte(rargs[3]), &locs,
   389→	); err != nil {
   390→		return fmt.Errorf(
   391→			"invalid locations JSON: %w", err,
   392→		)
   393→	}
   394→	locations := make([]textapi.Location, len(locs))
   395→	for i, l := range locs {
   396→		locations[i] = textapi.Location{
   397→			From: term.Coordinates{
   398→				X: l.From.X, Y: l.From.Y,
   399→			},
   400→			To: term.Coordinates{
   401→				X: l.To.X, Y: l.To.Y,
   402→			},
   403→			Message: l.Message,
   404→		}
   405→	}
   406→	h, err := getEditorHandler(ctx, c.app, rargs[0])
   407→	if err != nil {
   408→		return err
   409→	}
   410→	w, err := c.app.getWorkspace()
   411→	if err != nil {
   412→		return err
   413→	}
   414→	err = w.Editor(ctx).SetLocationList(
   415→		h, priority, id,
   416→		textapi.LocationSlice(locations),
   417→	)
   418→	if err != nil {
   419→		return err
   420→	}
   421→	return printOK(c.format)
   422→}
