		"wm":      newWMCLI(a),
		"storage": newStorageCLI(a),
		"editor":  newEditorCLI(a),
		"syntax":  newSyntaxCLI(a),
	}
	return &rootCLI{app: a, fs: fs, cmds: cmds}
}

func (r *rootCLI) Run(
