			" <json-locations>\n" +
			"  priority: info|warning|error|critical\n" +
			"  json-locations: " +
			`[{"from":{"x":N,"y":N},` +
			`"to":{"x":N,"y":N},` +
			`"message":"..."},...]`,
		Options: *c.fs,
	}
}

