func newWMSplitCLI(a *app) *wmSplitCLI {
	c := &wmSplitCLI{app: a}
	c.fs = cli.NewFlagSet("runectrl wm split")
	c.fs.StringVar(
		&c.format, "F", "",
		"Output format: table, json, or Go template",
	)
	c.fs.StringVar(
		&c.orientation, "o", "default",
		"Orientation: default|top|bottom|left|right",
	)
	return c
