	default:
		return 0, fmt.Errorf(
			"invalid orientation %q:"+
				" use default|top|bottom|left|right", s,
		)
	}
}

func parseAlignment(
	s string,
) (component.Alignment, error) {
	switch s {
	case "", "default":
		return 0, nil
	case "left":
		return component.AlignmentLeft, nil
	case "right":
		return component.AlignmentRight, nil
	case "top":
