				Alignment: alignment,
				Offset: term.Coordinates{
					X: offsetX, Y: offsetY,
				},
			}
			w, err := a.getWorkspace()
			if err != nil {
				return err
			}
			win, err := w.WindowManager(cmd.Context()).Floating(fh, cfg)
