func TestLooksLikeURI(t *testing.T) {
	tests := []struct {
		name string
		arg  string
		want bool
	}{
		{
			name: "file_uri",
			arg:  "file:///tmp/test.txt",
			want: true,
		},
		{
			name: "http_uri",
			arg:  "http://example.com/path",
			want: true,
		},
		{
			name: "https_uri",
			arg:  "https://example.com/path",
			want: true,
		},
		{
			name: "custom_scheme",
			arg:  "rune://workspace/file.txt",
			want: true,
		},
		{
			name: "absolute_path",
			arg:  "/tmp/test.txt",
			want: false,
		},
		{
			name: "relative_path",
			arg:  "./test.txt",
			want: false,
		},
		{
			name: "relative_path_no_dot",
			arg:  "test.txt",
			want: false,
		},
		{
			name: "windows_path",
			arg:  "C:\\Users\\test.txt",
			want: false,
		},
		{
			name: "empty_string",
			arg:  "",
			want: false,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := looksLikeURI(tt.arg)
			require.Equal(t, tt.want, got)
		})
	}
}

func TestResolveURIArgWithURI(t *testing.T) {
	tests := []struct {
		name    string
		arg     string
		wantURI string
		wantErr bool
	}{
		{
			name:    "file_uri",
			arg:     "file:///tmp/test.txt",
			wantURI: "file:///tmp/test.txt",
		},
		{
			name:    "rune_uri",
			arg:     "rune://workspace/src/main.go",
			wantURI: "rune://workspace/src/main.go",
		},
		{
			name:    "uri_with_query",
			arg:     "file:///tmp/test.txt?line=10",
			wantURI: "file:///tmp/test.txt?line=10",
		},
		{
			name:    "invalid_uri",
			arg:     "://invalid",
			wantErr: true,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			a := &app{}
			got, err := a.resolveURIArg(
				context.Background(), tt.arg,
			)
			if tt.wantErr {
				require.Error(t, err)
				return
			}
			require.NoError(t, err)
			require.Equal(t, tt.wantURI, got.String())
		})
	}
}

